mapper.sql:
SELECT A.SEQ_NUM , A.CUSTOMER_ID , A.CONTRACT_NUM , A.SUBSCRIBER_NO , A.CSTMR_NM , A.CUSTOMER_TYPE , FN_GET_CODENM('RCP0022', A.CUSTOMER_TYPE) AS CUSTOMER_TYPE_NM , A.USER_SSN , FN_GET_CODENM('MSP0003', A.SUB_STATUS) AS SUB_STATUS_NM , DECODE(A.PPPO, 'PO', '후불', '선불') AS PPPO , A.OPEN_DT , A.TMNT_DT , A.CSTMR_ADDR , A.INVST_VAL , A.INVST_TYPE , FN_GET_CODENM('CMN0107', A.INVST_TYPE) AS INVST_TYPE_NM , A.INVST_NM , A.REQ_TYPE , FN_GET_CODENM('CMN0108', A.REQ_TYPE) AS REQ_TYPE_NM , FN_GET_USRNM(A.PROCR_ID) AS PROCR_NM , A.PROC_DT , FN_GET_CODENM('RCP9020', A.INVST_LOC) AS INVST_LOC , REQ_ODTY , REQ_USER , APP_ODTY_NM , APP_USER , REQ_RSN , REQ_DTTM , EMAIL FROM MSP_INVST_REQ_MST A WHERE A.PROC_DT BETWEEN #{procDateS} AND #{procDateE}
AND A.SUBSCRIBER_NO = #{searchVal}
AND A.USER_SSN LIKE#{searchVal} || '%'
AND A.CONTRACT_NUM = #{searchVal}
AND A.INVST_NM LIKE #{invstVal} || '%'
AND A.INVST_TYPE = #{invstType} AND A.INVST_NM = #{invstVal}
AND A.REQ_TYPE = #{reqType}
AND A.INVST_VAL LIKE #{reqDoc} || '%'
ORDER BY A.SEQ_NUM DESC, A.PROC_DT DESC

mapper.select:
/* idntMgmtMapper.getInvstNmValListEx */

SELECT
    invst_nm
  , invst_val
FROM    MSP_INVST_REQ_MST A
WHERE   A.PROC_DT BETWEEN #{procDateS} AND #{procDateE} 



			AND A.SUBSCRIBER_NO = #{searchVal}


			AND A.USER_SSN LIKE#{searchVal} || '%'


			AND A.CONTRACT_NUM = #{searchVal}




	AND A.INVST_NM LIKE #{invstVal} || '%'


	AND A.INVST_TYPE = #{invstType}
	AND A.INVST_NM = #{invstVal}


	AND A.REQ_TYPE = #{reqType}


	AND A.INVST_VAL LIKE #{reqDoc} || '%'



		AND SEQ_NUM IN

			#{item}




GROUP BY
    invst_nm
  , invst_val

/* idntMgmtMapper.getInvstReqListSelectedEx */
SELECT A.SEQ_NUM , A.CUSTOMER_ID , A.CONTRACT_NUM , A.SUBSCRIBER_NO , A.CSTMR_NM , A.CUSTOMER_TYPE , FN_GET_CODENM('RCP0022', A.CUSTOMER_TYPE) AS CUSTOMER_TYPE_NM , A.USER_SSN , FN_GET_CODENM('MSP0003', A.SUB_STATUS) AS SUB_STATUS_NM , DECODE(A.PPPO, 'PO', '후불', '선불') AS PPPO , A.OPEN_DT , A.TMNT_DT , A.CSTMR_ADDR , A.INVST_VAL , A.INVST_TYPE , FN_GET_CODENM('CMN0107', A.INVST_TYPE) AS INVST_TYPE_NM , A.INVST_NM , A.REQ_TYPE , FN_GET_CODENM('CMN0108', A.REQ_TYPE) AS REQ_TYPE_NM , FN_GET_USRNM(A.PROCR_ID) AS PROCR_NM , A.PROC_DT , FN_GET_CODENM('RCP9020', A.INVST_LOC) AS INVST_LOC , REQ_ODTY , REQ_USER , APP_ODTY_NM , APP_USER , REQ_RSN , REQ_DTTM , EMAIL FROM MSP_INVST_REQ_MST A WHERE A.PROC_DT BETWEEN #{procDateS} AND #{procDateE}
AND A.INVST_NM = #{invstVal}
AND A.INVST_VAL = #{reqDoc}
AND SEQ_NUM IN
#{item}
ORDER BY A.SEQ_NUM DESC, A.PROC_DT DESC

/* idntMgmtMapper.getSeqNum */
SELECT  TO_CHAR(SYSDATE, 'YYYYMM') || LPAD(SQ_INVST_REQ.NEXTVAL, 6, '0') AS seqNum
FROM    DUAL

/* idntMgmtMapper.getCusType */
SELECT  NVL(B.CUSTOMER_TYPE, 'I')
 FROM MSP_JUO_SUB_INFO A, MSP_JUO_CUS_INFO B
WHERE A.CONTRACT_NUM = #{contractNum}
   AND A.CUSTOMER_ID = B.CUSTOMER_ID

/* idntMgmtMapper.getBeforeSaveCheck */
SELECT
    COUNT(*) CNT
FROM
    MSP_INVST_REQ_MST
WHERE 1=1
    AND INVST_TYPE = #{invstType} 
    AND INVST_NM = #{invstNm} 
    AND INVST_VAL = #{invstVal}

mapper.insert:
/*idntMgmtMapper.savInvstReq */

	SELECT  TO_CHAR(SYSDATE, 'YYYYMM') || LPAD(SQ_INVST_REQ.NEXTVAL, 6, '0') AS seqNum 
	FROM    DUAL

	INSERT INTO MSP_INVST_REQ_MST (
	   SEQ_NUM
	   , SEARCH_TYPE
	   , CONTRACT_NUM
	   , CUSTOMER_ID
	   , SUBSCRIBER_NO
	   , CSTMR_NM
	   , CUSTOMER_TYPE
	   , USER_SSN
	   , SUB_STATUS
	   , PPPO
	   , OPEN_DT
	   , TMNT_DT
	   , CSTMR_ADDR
	   , INVST_VAL
	   , INVST_TYPE
	   , INVST_NM
	   , REQ_TYPE
	   , PROCR_ID
	   , PROC_DT
	   , REGST_DTTM
	   , INVST_LOC
	   , REQ_ODTY
	   , REQ_USER
	   , APP_ODTY
	   , APP_ODTY_NM
	   , APP_USER
	   , REQ_RSN
	   , REQ_DTTM
	   , EMAIL
	) VALUES (
	    #{seqNum, jdbcType=VARCHAR}
	    , DECODE(#{searchGb, jdbcType=VARCHAR}, '00', '10', '08', '10', '20')
	    , #{contractNum, jdbcType=VARCHAR}
	    , #{customerId, jdbcType=VARCHAR}
	    , #{subscriberNo, jdbcType=VARCHAR}
	    , #{cstmrNm, jdbcType=VARCHAR}
	    , #{searchGb, jdbcType=VARCHAR}
	    , #{userSsn, jdbcType=VARCHAR}
	    , #{subStatus, jdbcType=VARCHAR}
	    , #{pppo, jdbcType=VARCHAR}
	    , #{openDt, jdbcType=VARCHAR}
	    , #{tmntDt, jdbcType=VARCHAR}
	    , #{cstmrAddr, jdbcType=VARCHAR}
	    , #{invstVal, jdbcType=VARCHAR}
	    , #{invstType, jdbcType=VARCHAR}
	    , #{invstNm, jdbcType=VARCHAR}
	    , #{reqType, jdbcType=VARCHAR}
	    , #{sessionUserId, jdbcType=VARCHAR}
	    , TO_CHAR(SYSDATE, 'YYYYMMDD')
	    , SYSDATE
	    , #{invstLoc, jdbcType=VARCHAR}
	    , #{reqOdty, jdbcType=VARCHAR}
	    , #{reqUser, jdbcType=VARCHAR}
	    , #{appOdty, jdbcType=VARCHAR}
	    , #{appOdtyNm, jdbcType=VARCHAR}
	    , #{appUser, jdbcType=VARCHAR}
	    , #{reqRsn, jdbcType=VARCHAR}
	    , #{reqDttm}
	    , #{email}
	)

mapper.select:
/* idntMgmtMapper.getInvstCusInfoValidation */
SELECT '1'
FROM  CMN_GRP_CD_MST
WHERE 1 = 1
  AND GRP_ID = #{grpId}
  AND USG_YN = 'Y'
  AND CD_VAL = #{cdVal}

/* idntMgmtMapper.getAppOdtyNm */
SELECT CD_DSC FROM CMN_GRP_CD_MST
WHERE GRP_ID = #{searchVal}
     AND CD_VAL = #{appOdty}

mapper.delete:
/* idntMgmtMapper.deleteMspInvstReqMst */
DELETE  MSP_INVST_REQ_MST
WHERE SEQ_NUM = #{seqNum, jdbcType=VARCHAR}
